import React, {useState} from 'react';
function Login(props) {
    const {email, password, login} = props;
    const [username, setUsername] = useState('');
    const [pass, setPass] = useState('');



    const handleEmail = (event) => {
        setUsername(event.target.value);
    }
    const handlePassword = (event) => {
        setPass(event.target.value);
    }

    const handleSubmit = (event) => {
        event.preventDefault();
        console.log(username, pass);
    }



    return (
        <div className="login position-absolute top-50 start-50 translate-middle p-4">
            <h2 className="Welcome_text">Welcome back!</h2>
            <div className="login_content p-2">
                <h5 className="Login_text">Email</h5>
                <input
                    className="login_input"
                    type="text"
                    value={email}
                    onChange = {handleEmail}
                ></input>
            </div>
            <div className="Password_content p-2">
                <h5 className="Password_text">Password</h5>
                <input
                    className="Password_input"
                    type="text"
                    value={password}
                    onChange = {handlePassword}
                ></input>
                <p className="Forgot_password py-0 m-0">Forgot your password?</p>
            </div>
            <div className="btn_container p-2">
                <button
                    type="button"
                    className="login_btn"
                    onClick={handleSubmit}
                >
                    Login
                </button>
                <p className="Register py-0 m-0">Need an account? <a>Register</a></p>
            </div>
        </div>
    );
}

export default Login;
